  1→//! Bidirectional conversions between canonical Agent OS types and rmcp MCP types.
  2→//!
  3→//! - [`definition_to_mcp_tool`]: canonical [`ToolDefinition`] → rmcp [`McpToolDef`]
  4→//! - [`mcp_result_to_call_result`]: canonical [`ToolResult`] → rmcp [`CallToolResult`]
  5→
  6→use aios_protocol::tool::{
  7→    ToolAnnotations as CanonicalAnnotations, ToolContent, ToolDefinition, ToolResult,
  8→};
  9→use rmcp::model::{CallToolResult, Content, Tool as McpToolDef, ToolAnnotations as McpAnnotations};
 10→use serde_json::Value;
 11→use std::borrow::Cow;
 12→use std::sync::Arc;
 13→
 14→/// Convert a canonical [`ToolDefinition`] to an rmcp [`McpToolDef`].
 15→///
 16→/// The MCP protocol requires `input_schema` to be a JSON Object (`Map<String, Value>`).
 17→/// If the canonical schema is not an object, this wraps it under `{"type": "object"}`.
 18→pub fn definition_to_mcp_tool(def: &ToolDefinition) -> McpToolDef {
 19→    let input_schema = match &def.input_schema {
 20→        Value::Object(map) => Arc::new(map.clone()),
 21→        _ => Arc::new(serde_json::Map::from_iter([(
 22→            "type".to_string(),
 23→            Value::String("object".to_string()),
 24→        )])),
 25→    };
 26→
 27→    let output_schema = def.output_schema.as_ref().and_then(|s| match s {
 28→        Value::Object(map) => Some(Arc::new(map.clone())),
 29→        _ => None,
 30→    });
 31→
 32→    let annotations = def.annotations.as_ref().map(canonical_to_mcp_annotations);
 33→
 34→    McpToolDef {
 35→        name: Cow::Owned(def.name.clone()),
 36→        title: def.title.clone(),
 37→        description: Some(Cow::Owned(def.description.clone())),
 38→        input_schema,
 39→        output_schema,
 40→        annotations,
 41→        execution: None,
 42→        icons: None,
 43→        meta: None,
 44→    }
 45→}
 46→
 47→/// Convert canonical [`ToolAnnotations`] to rmcp [`McpAnnotations`].
 48→fn canonical_to_mcp_annotations(ann: &CanonicalAnnotations) -> McpAnnotations {
 49→    McpAnnotations {
 50→        title: None,
 51→        read_only_hint: Some(ann.read_only),
 52→        destructive_hint: Some(ann.destructive),
 53→        idempotent_hint: Some(ann.idempotent),
 54→        open_world_hint: Some(ann.open_world),
 55→    }
 56→}
 57→
 58→/// Convert a canonical [`ToolResult`] to an rmcp [`CallToolResult`].
 59→pub fn tool_result_to_call_result(result: &ToolResult) -> CallToolResult {
 60→    let content: Vec<Content> = match &result.content {
 61→        Some(blocks) => blocks.iter().map(canonical_content_to_mcp).collect(),
 62→        None => {
 63→            // Fall back to output field as text
 64→            let text = match &result.output {
 65→                Value::String(s) => s.clone(),
 66→                other => other.to_string(),
 67→            };
 68→            vec![Content::text(text)]
 69→        }
 70→    };
 71→
 72→    // Include structured content from the JSON output when it's an object
 73→    let structured_content = match &result.output {
 74→        Value::Object(_) => Some(result.output.clone()),
 75→        _ => None,
 76→    };
 77→
 78→    CallToolResult {
 79→        content,
 80→        structured_content,
 81→        is_error: Some(result.is_error),
 82→        meta: None,
 83→    }
 84→}
 85→
 86→/// Convert a single canonical [`ToolContent`] block to an rmcp [`Content`].
 87→fn canonical_content_to_mcp(content: &ToolContent) -> Content {
 88→    match content {
 89→        ToolContent::Text { text } => Content::text(text.clone()),
 90→        ToolContent::Image { data, mime_type } => Content::image(data.clone(), mime_type.clone()),
 91→        ToolContent::Json { value } => {
 92→            // json() returns Result; fall back to text serialization on error
 93→            Content::json(value).unwrap_or_else(|_| Content::text(value.to_string()))
 94→        }
 95→    }
 96→}
 97→
 98→#[cfg(test)]
 99→mod tests {
100→    use super::*;
101→    use aios_protocol::tool::ToolAnnotations as CanonicalAnnotations;
102→    use serde_json::json;
103→
104→    #[test]
105→    fn definition_to_mcp_tool_full() {
106→        let def = ToolDefinition {
107→            name: "read_file".into(),
108→            description: "Read a file".into(),
109→            input_schema: json!({
110→                "type": "object",
111→                "properties": { "path": { "type": "string" } },
112→                "required": ["path"]
113→            }),
114→            title: Some("Read File".into()),
115→            output_schema: Some(json!({"type": "string"})),
116→            annotations: Some(CanonicalAnnotations {
117→                read_only: true,
118→                destructive: false,
119→                idempotent: true,
120→                open_world: false,
121→                requires_confirmation: false,
122→            }),
123→            category: Some("filesystem".into()),
124→            tags: vec!["fs".into()],
125→            timeout_secs: Some(30),
126→        };
127→
128→        let mcp = definition_to_mcp_tool(&def);
129→        assert_eq!(mcp.name.as_ref(), "read_file");
130→        assert_eq!(mcp.description.as_deref(), Some("Read a file"));
131→        assert_eq!(mcp.title.as_deref(), Some("Read File"));
132→        assert!(mcp.output_schema.is_some());
133→
134→        let ann = mcp.annotations.unwrap();
135→        assert_eq!(ann.read_only_hint, Some(true));
136→        assert_eq!(ann.destructive_hint, Some(false));
137→        assert_eq!(ann.idempotent_hint, Some(true));
138→        assert_eq!(ann.open_world_hint, Some(false));
139→    }
140→
141→    #[test]
142→    fn definition_to_mcp_tool_minimal() {
143→        let def = ToolDefinition {
144→            name: "simple".into(),
145→            description: "A simple tool".into(),
146→            input_schema: json!({"type": "object"}),
